@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');

:root {
    --bg-color: #1a1a2e;
    --card-bg-color: rgba(255, 255, 255, 0.1);
    --card-border-color: rgba(255, 255, 255, 0.2);
    --text-color: #e0e0e0;
    --primary-color: #0f3460;
    --secondary-color: #e94560;
    --tertiary-color: #533483;
    --shadow-color: rgba(0, 0, 0, 0.3);
    --gradient-start: #0a1128;
    --gradient-end: #03081a;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Poppins', sans-serif;
    background: linear-gradient(135deg, var(--gradient-start), var(--gradient-end));
    color: var(--text-color);
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
    overflow-x: hidden;
}

#app {
    display: flex;
    flex-direction: column;
    gap: 30px;
    width: 100%;
    max-width: 1200px;
    margin: 0 auto;
}

.dashboard-header {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    align-items: center;
    gap: 20px;
    padding: 25px;
    background: var(--card-bg-color);
    border-radius: 20px;
    backdrop-filter: blur(15px);
    border: 1px solid var(--card-border-color);
    box-shadow: 0 8px 32px 0 var(--shadow-color);
    transition: all 0.3s ease;
}

.search-container {
    display: flex;
    flex-grow: 1;
    max-width: 400px;
}

.search-input {
    flex-grow: 1;
    padding: 12px 20px;
    border: none;
    border-radius: 15px 0 0 15px;
    background: rgba(255, 255, 255, 0.15);
    color: var(--text-color);
    font-size: 1rem;
    outline: none;
    transition: background 0.3s ease, box-shadow 0.3s ease;
}

.search-input::placeholder {
    color: rgba(255, 255, 255, 0.6);
}

.search-input:focus {
    background: rgba(255, 255, 255, 0.25);
    box-shadow: 0 0 0 2px var(--secondary-color);
}

.search-button {
    padding: 12px 20px;
    border: none;
    border-radius: 0 15px 15px 0;
    background: var(--secondary-color);
    color: #fff;
    font-size: 1.1rem;
    cursor: pointer;
    transition: background 0.3s ease, transform 0.2s ease;
}

.search-button:hover {
    background: #c73450;
    transform: translateY(-2px);
}

.unit-toggle-container {
    display: flex;
    align-items: center;
    gap: 10px;
}

.unit-label {
    font-size: 1.1rem;
    font-weight: 500;
}

/* The switch - the box around the slider */
.switch {
    position: relative;
    display: inline-block;
    width: 60px;
    height: 34px;
}

/* Hide default HTML checkbox */
.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

/* The slider */
.slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: var(--primary-color);
    transition: .4s;
    border-radius: 34px;
}

.slider:before {
    position: absolute;
    content: "";
    height: 26px;
    width: 26px;
    left: 4px;
    bottom: 4px;
    background-color: white;
    transition: .4s;
    border-radius: 50%;
}

input:checked + .slider {
    background-color: var(--secondary-color);
}

input:focus + .slider {
    box-shadow: 0 0 1px var(--secondary-color);
}

input:checked + .slider:before {
    transform: translateX(26px);
}

/* Rounded sliders */
.slider.round {
    border-radius: 34px;
}

.slider.round:before {
    border-radius: 50%;
}

.dashboard-main {
    display: grid;
    grid-template-columns: 1fr;
    gap: 30px;
    position: relative; /* For spinner positioning */
}

.weather-card {
    background: var(--card-bg-color);
    border-radius: 20px;
    backdrop-filter: blur(15px);
    border: 1px solid var(--card-border-color);
    box-shadow: 0 8px 32px 0 var(--shadow-color);
    padding: 30px;
    transition: all 0.3s ease;
    opacity: 0;
    transform: translateY(20px);
    visibility: hidden;
}

.weather-card.visible {
    opacity: 1;
    transform: translateY(0);
    visibility: visible;
}

.current-weather {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
}

.city-name {
    font-size: 2.5rem;
    font-weight: 700;
    margin-bottom: 10px;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.4);
}

.current-date {
    font-size: 1.1rem;
    opacity: 0.8;
    margin-bottom: 20px;
}

.weather-summary {
    display: flex;
    flex-direction: column;
    align-items: center;
    margin-bottom: 30px;
    gap: 15px;
}

.weather-summary .weather-icon {
    width: 120px;
    height: 120px;
    filter: drop-shadow(0 5px 10px rgba(0, 0, 0, 0.3));
}

.current-temp {
    font-size: 4rem;
    font-weight: 600;
    line-height: 1;
    margin-bottom: 5px;
    text-shadow: 2px 2px 6px rgba(0, 0, 0, 0.5);
}

.weather-description {
    font-size: 1.3rem;
    font-weight: 500;
    text-transform: capitalize;
    opacity: 0.9;
}

.weather-details {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 20px;
    width: 100%;
    max-width: 800px;
    margin-top: 20px;
}

.detail-item {
    display: flex;
    align-items: center;
    gap: 10px;
    background: rgba(255, 255, 255, 0.08);
    padding: 15px 20px;
    border-radius: 15px;
    font-size: 1rem;
    font-weight: 400;
    transition: background 0.3s ease;
}

.detail-item:hover {
    background: rgba(255, 255, 255, 0.15);
}

.detail-item i {
    color: var(--secondary-color);
    font-size: 1.2rem;
}

.forecast-section {
    padding: 30px;
}

.section-title {
    font-size: 1.8rem;
    font-weight: 600;
    margin-bottom: 25px;
    text-align: center;
    text-shadow: 1px 1px 3px rgba(0, 0, 0, 0.3);
}

.forecast-container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
    gap: 20px;
}

.forecast-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: rgba(255, 255, 255, 0.08);
    padding: 20px 10px;
    border-radius: 15px;
    transition: transform 0.3s ease, background 0.3s ease;
    text-align: center;
}

.forecast-item:hover {
    transform: translateY(-5px);
    background: rgba(255, 255, 255, 0.15);
}

.forecast-item .day {
    font-size: 1rem;
    font-weight: 500;
    margin-bottom: 8px;
    opacity: 0.9;
}

.forecast-item .forecast-icon {
    width: 60px;
    height: 60px;
    margin-bottom: 8px;
    filter: drop-shadow(0 3px 6px rgba(0, 0, 0, 0.2));
}

.forecast-item .temps {
    font-size: 1.1rem;
    font-weight: 600;
    display: flex;
    gap: 5px;
}

.forecast-item .temps .high {
    color: var(--secondary-color);
}

.forecast-item .temps .low {
    opacity: 0.7;
}

/* Loading Spinner */
.loading-spinner {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 10;
    background: rgba(0, 0, 0, 0.6);
    border-radius: 20px;
    padding: 30px;
    display: flex;
    justify-content: center;
    align-items: center;
    transition: opacity 0.3s ease;
}

.loading-spinner.hidden {
    opacity: 0;
    pointer-events: none;
}

.spinner {
    border: 8px solid rgba(255, 255, 255, 0.3);
    border-top: 8px solid var(--secondary-color);
    border-radius: 50%;
    width: 60px;
    height: 60px;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}

/* Utility classes */
.hidden {
    display: none;
}

/* Responsive Design */
@media (max-width: 992px) {
    .dashboard-header {
        flex-direction: column;
        align-items: stretch;
        padding: 20px;
    }

    .search-container {
        max-width: 100%;
    }

    .unit-toggle-container {
        justify-content: center;
    }

    .city-name {
        font-size: 2rem;
    }

    .current-temp {
        font-size: 3.5rem;
    }

    .weather-description {
        font-size: 1.1rem;
    }

    .weather-details {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 768px) {
