*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

:root {
    --black: #000000;
    --white: #FFFFFF;
    --red: #FF3B30;
    --green: #00C853;
    --yellow: #FFCC00;
    --blue: #007AFF;
    --pink: #FF2D92;
    --orange: #FF9500;
    --purple: #AF52DE;
    --border-width: 4px;
    --shadow-offset: 6px;
    --shadow-color: var(--black);
    --font-display: 'Press Start 2P', monospace;
    --font-body: 'Courier New', Courier, monospace;
}

body {
    background-color: var(--black);
    background-image:
        linear-gradient(45deg, #111 25%, transparent 25%),
        linear-gradient(-45deg, #111 25%, transparent 25%),
        linear-gradient(45deg, transparent 75%, #111 75%),
        linear-gradient(-45deg, transparent 75%, #111 75%);
    background-size: 20px 20px;
    background-position: 0 0, 0 10px, 10px -10px, -10px 0px;
    background-attachment: fixed;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    padding: 16px;
    font-family: var(--font-body);
}

.calculator-wrapper {
    width: 100%;
    max-width: 420px;
    position: relative;
}

.calculator {
    background-color: var(--white);
    border: var(--border-width) solid var(--black);
    border-radius: 0;
    box-shadow: var(--shadow-offset) var(--shadow-offset) 0px var(--black);
    padding: 24px;
    position: relative;
}

.calc-label {
    font-family: var(--font-display);
    font-size: 10px;
    color: var(--black);
    text-align: center;
    margin-bottom: 16px;
    letter-spacing: 2px;
}

.memory-indicator {
    position: absolute;
    top: 12px;
    right: 12px;
    font-family: var(--font-display);
    font-size: 8px;
    color: var(--yellow);
    background: var(--black);
    padding: 4px 6px;
    border: 2px solid var(--yellow);
    display: none;
}

.memory-indicator.active {
    display: block;
}

.display-container {
    background-color: #0a0a0a;
