document.addEventListener('DOMContentLoaded', () => {
    const display = document.getElementById('display');
    const expressionDisplay = document.getElementById('expressionDisplay');
    const memoryIndicator = document.getElementById('memoryIndicator');
    const buttons = document.querySelectorAll('.btn');

    let currentInput = '0';
    let previousInput = '';
    let operator = null;
    let shouldResetDisplay = false;
    let memory = 0;
    let lastExpression = '';

    const MAX_DIGITS = 15;

    function updateDisplay() {
        let displayValue = currentInput;
        if (currentInput.includes('.')) {
            const parts = currentInput.split('.');
            const intPart = parts[0];
            const decPart = parts[1];
            if (intPart.length > MAX_DIGITS) {
                displayValue = Number(currentInput).toExponential(6);
            }
        } else if (currentInput.length > MAX_DIGITS) {
            displayValue = Number(currentInput).toExponential(6);
        }
        display.textContent = displayValue;
    }

    function setExpression(text) {
        expressionDisplay.textContent = text;
    }

    function updateMemoryIndicator() {
        if (memory !== 0) {
            memoryIndicator.classList.add('active');
        } else {
            memoryIndicator.classList.remove('active');
        }
    }

    function triggerGlitch() {
        display.classList.add('glitch');
        setTimeout(() => display.classList.remove('glitch'), 200);
    }

    function inputNumber(num) {
        if (currentInput === 'Error') clearAll();
        if (shouldResetDisplay) {
            currentInput = num;
            shouldResetDisplay = false;
        } else {
            if (currentInput === '0' && num !== '0') {
                currentInput = num;
            } else if (currentInput === '0' && num === '0') {
                return;
            } else {
                if (currentInput.replace(/[^0-9]/g, '').length >= MAX_DIGITS) return;
                currentInput += num;
            }
        }
        updateDisplay();
    }

    function inputDecimal() {
        if (currentInput === 'Error') clearAll();
        if (shouldResetDisplay) {
            currentInput = '0.';
            shouldResetDisplay = false;
        } else if (!currentInput.includes('.')) {
            currentInput += '.';
        }
        updateDisplay();
    }

    function inputOperator(op) {
        if (currentInput === 'Error') return;
        if (operator && !shouldResetDisplay) {
            calculate();
        }
        previousInput = currentInput;
        operator = op;
        shouldResetDisplay = true;
        const opSymbol = op === '−' ? '−' : op === '×' ? '×' : op === '÷' ? '÷' : op;
        setExpression(`${previousInput} ${opSymbol}`);
    }

    function calculate() {
        if (!operator || !previousInput) return;
        const prev = parseFloat(previousInput);
        const curr = parseFloat(currentInput);
        if (isNaN(prev) || isNaN(curr)) return;
        let result;
        switch (operator) {
            case '+': result = prev + curr; break;
            case '−': result = prev - curr; break;
            case '×': result = prev * curr; break;
            case '÷':
                if (curr === 0) {
                    currentInput = 'Error';
                    setExpression('');
                    updateDisplay();
                    operator = null;
                    previousInput = '';
                    shouldResetDisplay = true;
                    triggerGlitch();
                    return;
                }
                result = prev / curr;
                break;
            default: return;
        }
        if (!isFinite(result)) {
            currentInput = 'Error';
            setExpression('');
            updateDisplay();
            operator = null;
            previousInput = '';
            shouldResetDisplay = true;
            triggerGlitch();
            return;
        }
        const opSymbol = operator === '−' ? '−' : operator === '×' ? '×' : operator === '÷' ? '÷' : operator;
        lastExpression = `${previousInput} ${opSymbol} ${currentInput} =`;
        setExpression(lastExpression);
        currentInput = parseFloat(result.toPrecision(12)).toString();
        operator = null;
        previousInput = '';
        shouldResetDisplay = true;
        updateDisplay();
    }

    function equals() {
        if (currentInput === 'Error') return;
        if (operator && previousInput) {
            calculate();
        }
    }

    function clearEntry() {
        currentInput = '0';
        updateDisplay();
    }

    function clearAll() {
        currentInput = '0';
        previousInput = '';
        operator = null;
        shouldResetDisplay = false;
        setExpression('');
        updateDisplay();
    }

    function backspace() {
        if (currentInput === 'Error') {
            clearAll();
            return;
        }
        if (shouldResetDisplay) return;
        if (currentInput.length === 1 || (currentInput.length === 2 && currentInput.startsWith('-'))) {
            currentInput = '0';
        } else {
            currentInput = currentInput.slice(0, -1);
        }
        updateDisplay();
    }

    function percent() {
        if (currentInput === 'Error') return;
        const val = parseFloat(currentInput);
        if (isNaN(val)) return;
        currentInput = (val / 100).toString();
        updateDisplay();
    }

    function memoryClear() {
        memory = 0;
        updateMemoryIndicator();
    }

    function memoryRecall() {
        if (memory !== 0 || memory === 0) {
            currentInput = parseFloat(memory.toPrecision(12)).toString();
            shouldResetDisplay = true;
            updateDisplay();
        }
    }

    function memoryAdd() {
        const val = parseFloat(currentInput);
        if (isNaN(val)) return;
        memory += val;
        updateMemoryIndicator();
        shouldResetDisplay = true;
    }

    function memorySubtract() {
        const val = parseFloat(currentInput);
        if (isNaN(val)) return;
        memory -= val;
        updateMemoryIndicator();
        shouldResetDisplay = true;
    }

    function handleButtonAction(action, value) {
        switch (action) {
            case 'number': inputNumber(value); break;
            case 'decimal': inputDecimal(); break;
            case 'operator': inputOperator(value); break;
            case 'equals': equals(); break;
            case 'ce': clearEntry(); break;
            case 'c': clearAll(); break;
            case 'backspace': backspace(); break;
            case 'percent': percent(); break;
            case 'mc': memoryClear(); break;
            case 'mr': memoryRecall(); break;
            case 'mplus': memoryAdd(); break;
            case 'mminus': memorySubtract(); break;
        }
    }

    buttons.forEach(btn => {
        btn.addEventListener('click', () => {
            const action = btn.dataset.action;
            const value = btn.dataset.value || null;
            handleButtonAction(action, value);
        });
    });

    document.addEventListener('keydown', (e) => {
        const key = e.key;
        let targetBtn = null;

        if (key >= '0' && key <= '9') {
            targetBtn = document.querySelector(`.btn[data-value="${key}"][data-action="number"]`);
            inputNumber(key);
        } else if (key === '.') {
            targetBtn = document.querySelector('.btn[data-action="decimal"]');
            inputDecimal();
        } else if (key === '+') {
            targetBtn = document.querySelector('.btn[data-value="+"]');
            inputOperator('+');
        } else if (key === '-') {
            targetBtn = document.querySelector('.btn[data-value="−"]');
            inputOperator('−');
        } else if (key === '*') {
            targetBtn = document.querySelector('.btn[data-value="×"]');
            inputOperator('×');
        } else if (key === '/') {
            e.preventDefault();
            targetBtn = document.querySelector('.btn[data-value="÷"]');
            inputOperator('÷');
        } else if (key === 'Enter' || key === '=') {
            e.preventDefault();
            targetBtn = document.querySelector('.btn[data-action="equals"]');
            equals();
        } else if (key === 'Backspace') {
            targetBtn = document.querySelector('.btn[data-action="backspace"]');
            backspace();
        } else if (key === 'Escape') {
            targetBtn = document.querySelector('.btn[data-action="c"]');
            clearAll();
        } else if (key === 'Delete') {
            targetBtn = document.querySelector('.btn[data-action="ce"]');
            clearEntry();
        } else if (key === '%') {
            targetBtn = document.querySelector('.btn[data-action="percent"]');
            percent();
        } else if (key === 'm' || key === 'M') {
            memoryRecall();
        }

        if (targetBtn) {
            targetBtn.classList.add('pressed');
            setTimeout(() => targetBtn.classList.remove('pressed'), 150);
        }
    });

    updateDisplay();
    updateMemoryIndicator();
});

